                double screenHeight = SystemParameters.WorkArea.Height;

                this.Left = (screenWidth - this.ActualWidth) / 2 + SystemParameters.WorkArea.Left;
                this.Top = (screenHeight - this.ActualHeight) / 2 + SystemParameters.WorkArea.Top;
            };

